import React from 'react';

// --- SECTION 1: SMALL CHOPS CURATES ---
const Menu = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  const items = [
    { name: "The Starter Pack", price: "7,500", desc: "Samosa, Springroll, Puff-puff, Mosa" },
    { name: "Signature Platter", price: "15,000", desc: "Chicken, Gizz-dodo, Samosa, Springroll" },
    { name: "Owambe Special", price: "25,000", desc: "Full variety with extra Peppered Protein" }
  ];

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '30px' }}>
      {items.map((item) => (
        <div key={item.name} style={{ border: `1px solid ${gold}22`, padding: '30px', textAlign: 'center', borderRadius: '4px' }}>
          <h4 style={{ color: gold, fontFamily: fancyFont, fontSize: '1.4rem' }}>{item.name}</h4>
          <p style={{ color: '#555', fontSize: '0.8rem', margin: '15px 0' }}>{item.desc}</p>
          <div style={{ color: gold, fontWeight: 'bold', fontSize: '1.1rem' }}>₦{item.price}</div>
          <button style={{ marginTop: '20px', background: 'none', border: `1px solid ${gold}`, color: gold, padding: '8px 20px', cursor: 'pointer', fontSize: '0.7rem', letterSpacing: '1px' }}>ADD TO BOX</button>
        </div>
      ))}
    </div>
  );
};

export default Menu;

// --- SECTION 2: THE OFFICE LUNCH EXPERIENCE ---
export const Lunch = () => {
  const gold = '#D4AF37';
  const fancyFont = "'Playfair Display', 'Georgia', serif";

  return (
    <div style={{ color: '#fff', padding: '20px', maxWidth: '900px', margin: '0 auto' }}>
      
      {/* 1. WHY LUNCH MATTERS */}
      <section style={{ textAlign: 'center', marginBottom: '60px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, fontSize: '2.5rem', fontStyle: 'italic' }}>
          Fueling Your Ambition
        </h3>
        <p style={{ color: '#888', maxWidth: '600px', margin: '15px auto', lineHeight: '1.6', fontSize: '1rem' }}>
          Your afternoon performance is decided by your midday plate. We provide the nutrient-dense fuel 
          required to keep your creativity sharp and your energy high.
        </p>
      </section>

      {/* 2. MORNING ENCOURAGEMENT CARD */}
      <section style={{ 
        backgroundColor: '#0A0A0A', 
        border: `1px solid ${gold}22`, 
        padding: '30px', 
        borderRadius: '8px', 
        textAlign: 'center',
        marginBottom: '60px' 
      }}>
        <h4 style={{ color: gold, marginBottom: '10px', fontSize: '1.2rem', fontFamily: fancyFont }}>Good Morning, Champion. ✨</h4>
        <p style={{ color: '#666', fontStyle: 'italic', fontSize: '0.9rem', marginBottom: '20px' }}>
          "Success is the sum of small efforts, repeated day in and day out."
        </p>
        <button style={{ 
          backgroundColor: gold, 
          color: '#000', 
          border: 'none', 
          padding: '12px 35px', 
          borderRadius: '2px', 
          fontWeight: 'bold',
          cursor: 'pointer',
          letterSpacing: '1px'
        }}>
          CLOCK IN FOR TODAY
        </button>
      </section>

      {/* 3. NUTRIENT DISPLAY */}
      <section style={{ marginBottom: '60px', textAlign: 'center' }}>
        <h4 style={{ fontFamily: fancyFont, color: gold, marginBottom: '25px', fontSize: '1.3rem' }}>Today's Nutritional Balance 🥗</h4>
        <div style={{ display: 'flex', justifyContent: 'center', gap: '40px', flexWrap: 'wrap' }}>
          {[
            { label: 'Energy', val: 'Complex Carbs' },
            { label: 'Muscle', val: 'Lean Protein' },
            { label: 'Focus', val: 'Healthy Fats' },
            { label: 'Vibe', val: '100% Organic 😊' }
          ].map((stat) => (
            <div key={stat.label} style={{ borderBottom: `1px solid ${gold}33`, padding: '10px 20px' }}>
              <div style={{ fontSize: '0.7rem', color: '#444', textTransform: 'uppercase', letterSpacing: '1px' }}>{stat.label}</div>
              <div style={{ fontSize: '1rem', color: '#fff', marginTop: '5px' }}>{stat.val}</div>
            </div>
          ))}
        </div>
      </section>

      {/* 4. THE EXTRAS (CURATE YOUR OWN) */}
      <section style={{ marginBottom: '60px' }}>
        <h3 style={{ fontFamily: fancyFont, color: gold, textAlign: 'center', marginBottom: '30px', fontSize: '1.8rem' }}>
          The À La Carte Add-ons
        </h3>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '15px' }}>
          {[
            { name: "Extra Protein Side", price: "₦2,500" },
            { name: "Daily Cold-Pressed Juice", price: "₦1,500" },
            { name: "Seasonal Fruit Parfait", price: "₦2,000" },
            { name: "Greek Salad Side", price: "₦1,800" }
          ].map((item) => (
            <div key={item.name} style={{ display: 'flex', justifyContent: 'space-between', padding: '20px', border: '1px solid #111', borderRadius: '4px' }}>
              <span style={{ color: '#888' }}>{item.name}</span>
              <span style={{ color: gold, fontWeight: 'bold' }}>{item.price}</span>
            </div>
          ))}
        </div>
      </section>

      {/* 5. SERVICE FEATURES */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '30px', borderTop: '1px solid #111', paddingTop: '50px' }}>
        <div style={{ textAlign: 'center' }}>
          <h5 style={{ color: gold, marginBottom: '10px', fontSize: '1rem' }}>📍 Precision Timing</h5>
          <p style={{ color: '#444', fontSize: '0.8rem', lineHeight: '1.4' }}>Direct desk delivery before peak hunger hits.</p>
        </div>
        <div style={{ textAlign: 'center' }}>
          <h5 style={{ color: gold, marginBottom: '10px', fontSize: '1rem' }}>🥗 Balanced Fuel</h5>
          <p style={{ color: '#444', fontSize: '0.8rem', lineHeight: '1.4' }}>Clean energy designed to eliminate the 3 PM slump.</p>
        </div>
        <div style={{ textAlign: 'center' }}>
          <h5 style={{ color: gold, marginBottom: '10px', fontSize: '1rem' }}>📦 Eco-Luxury</h5>
          <p style={{ color: '#444', fontSize: '0.8rem', lineHeight: '1.4' }}>Leak-proof, premium packaging for a mess-free desk.</p>
        </div>
      </div>
    </div>
  );
};
